select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = p.owneruserid and u.id = b.userid and p.id = c.postid and p.id = ph.postid and p.id = v.postid and c.score=0 and c.creationdate<=timestamp '2014-09-09 19:58:29' and p.score>=-4 and p.viewcount>=0 and p.viewcount<=5977 and p.answercount<=4 and p.commentcount>=0 and p.commentcount<=11 and p.creationdate>=timestamp '2011-01-25 08:31:41' and u.reputation<=312 and u.downvotes<=0;
